CREATE TABLE IF NOT EXISTS naf25_codes (
    niv5         VARCHAR(10) PRIMARY KEY,
    niv4         VARCHAR(10),
    niv3         VARCHAR(10),
    niv2         VARCHAR(10),
    niv1         VARCHAR(1),
    niv1_libelle TEXT,
    niv5_libelle TEXT
    );

CREATE INDEX IF NOT EXISTS idx_naf25_codes_niv5 ON naf25_codes(niv5);
CREATE INDEX IF NOT EXISTS idx_naf25_codes_niv1 ON naf25_codes(niv1);

